// src/AddOfficer.js
import React, { useState } from 'react';

const AddOfficer = () => {
  const [name, setName] = useState('');
  const [rank, setRank] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle the officer addition logic here
    console.log('Officer added:', { name, rank });
  };

  return (
    <div>
      <h2>Add Officer</h2>
      <form onSubmit={handleSubmit}>
        <div>
          <label>Name:</label>
          <input 
            type="text" 
            value={name} 
            onChange={(e) => setName(e.target.value)} 
            required 
          />
        </div>
        <div>
          <label>Rank:</label>
          <input 
            type="text" 
            value={rank} 
            onChange={(e) => setRank(e.target.value)} 
            required 
          />
        </div>
        <button type="submit">Add Officer</button>
      </form>
    </div>
  );
};

export default AddOfficer;
